// =====================================================
// Road — north of the village.
// Edges:  south -> village.map   (walk off the bottom)
// =====================================================

map MountainRoad {
  size 20, 14;

  neighbor south "village.map";

  // Stone-lined road heading uphill
  fill DIRT from (8,0) to (10,13);
  row PATH from (9,0) to (9,13);

  // Rocks along the cliffs
  tile ROCK at (3,2);
  tile ROCK at (4,5);
  tile ROCK at (2,7);
  tile ROCK at (3,10);
  tile ROCK at (5,12);

  tile ROCK at (14,2);
  tile ROCK at (16,5);
  tile ROCK at (15,8);
  tile ROCK at (17,11);

  // A pair of torches near the southern threshold
  tile TORCH at (8,12);
  tile TORCH at (10,12);

  // Wayside flowers
  tile FLOWER at (12,3);
  tile FLOWER at (13,4);
  tile FLOWER at (7,9);
}
